import sys
import heapq

def solve():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    t = int(data[idx])
    idx += 1
    for _ in range(t):
        n = int(data[idx])
        idx += 1
        a = list(map(int, data[idx:idx+n]))
        idx += n
        a.sort()
        freq = {}
        for num in a:
            if num < n:
                freq[num] = freq.get(num, 0) + 1
        mex = 0
        while mex in freq:
            mex += 1
        res = [-1] * (n + 1)
        ops = 0
        heap = []
        for i in range(n + 1):
            if i < mex:
                res[i] = ops
                if i in freq:
                    heapq.heappush(heap, -freq[i])
            elif i == mex:
                res[i] = ops
            else:
                if not heap:
                    break
                cnt = -heapq.heappop(heap)
                ops += cnt
                res[i] = ops
        print(' '.join(map(str, res)))

if __name__ == "__main__":
    solve()

